create extension if not exists pgcrypto;
create or replace function public.set_current_timestamp_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end; $$;
create table if not exists public.companies(id uuid primary key default gen_random_uuid(), owner_user_id uuid not null unique, name text not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.company_members(company_id uuid not null references public.companies(id) on delete cascade, user_id uuid not null, role text not null default 'owner' check (role in ('owner','admin','member')), created_at timestamptz not null default now(), updated_at timestamptz not null default now(), primary key(company_id,user_id));
create table if not exists public.company_settings(company_id uuid primary key references public.companies(id) on delete cascade, legal_name text, trade_name text, legal_form text, siret text, ape_code text, address_line1 text, address_line2 text, postal_code text, city text, country text default 'France', phone text, email text, subject_to_vat boolean, vat_number text, vat_regime text, default_vat_rate numeric(5,2) default 20, currency text default 'EUR', language text default 'fr', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.company_document_settings(company_id uuid primary key references public.companies(id) on delete cascade, quote_prefix text default 'DEV', quote_next_number integer default 1, invoice_prefix text default 'FAC', invoice_next_number integer default 1, contract_prefix text default 'CTR', contract_next_number integer default 1, credit_prefix text default 'AV', credit_next_number integer default 1, default_payment_terms text default '30 jours', default_payment_method text default 'Virement bancaire', quote_validity_days integer default 30, bank_account_holder text, iban text, bic text, bank_name text, accepted_payment_methods jsonb not null default '["Virement bancaire"]'::jsonb, legal_notice text, collection_fee_notice text, visible_mention text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.user_preferences(user_id uuid primary key, company_id uuid references public.companies(id) on delete set null, nav_preferences jsonb not null default '{}'::jsonb, table_preferences jsonb not null default '{}'::jsonb, onboarding_completed boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index if not exists company_members_user_idx on public.company_members(user_id);
create index if not exists user_preferences_company_idx on public.user_preferences(company_id);
create or replace function public.current_user_company_ids() returns table(company_id uuid) language sql stable as $$ select cm.company_id from public.company_members cm where cm.user_id=auth.uid() $$;
alter table public.companies enable row level security; alter table public.company_members enable row level security; alter table public.company_settings enable row level security; alter table public.company_document_settings enable row level security; alter table public.user_preferences enable row level security;
do $$ begin
if not exists (select 1 from pg_policies where schemaname='public' and tablename='companies' and policyname='companies_select_member') then create policy companies_select_member on public.companies for select using (owner_user_id=auth.uid() or id in (select company_id from public.current_user_company_ids())); end if;
if not exists (select 1 from pg_policies where schemaname='public' and tablename='companies' and policyname='companies_insert_owner') then create policy companies_insert_owner on public.companies for insert with check (owner_user_id=auth.uid()); end if;
if not exists (select 1 from pg_policies where schemaname='public' and tablename='companies' and policyname='companies_update_owner') then create policy companies_update_owner on public.companies for update using (owner_user_id=auth.uid()) with check (owner_user_id=auth.uid()); end if;
if not exists (select 1 from pg_policies where schemaname='public' and tablename='company_members' and policyname='company_members_select_member') then create policy company_members_select_member on public.company_members for select using (company_id in (select company_id from public.current_user_company_ids())); end if;
if not exists (select 1 from pg_policies where schemaname='public' and tablename='company_members' and policyname='company_members_insert_owner') then create policy company_members_insert_owner on public.company_members for insert with check (user_id=auth.uid() or company_id in (select id from public.companies where owner_user_id=auth.uid())); end if;
if not exists (select 1 from pg_policies where schemaname='public' and tablename='company_settings' and policyname='company_settings_member_all') then create policy company_settings_member_all on public.company_settings for all using (company_id in (select company_id from public.current_user_company_ids())) with check (company_id in (select company_id from public.current_user_company_ids())); end if;
if not exists (select 1 from pg_policies where schemaname='public' and tablename='company_document_settings' and policyname='company_document_settings_member_all') then create policy company_document_settings_member_all on public.company_document_settings for all using (company_id in (select company_id from public.current_user_company_ids())) with check (company_id in (select company_id from public.current_user_company_ids())); end if;
if not exists (select 1 from pg_policies where schemaname='public' and tablename='user_preferences' and policyname='user_preferences_self_all') then create policy user_preferences_self_all on public.user_preferences for all using (user_id=auth.uid()) with check (user_id=auth.uid()); end if;
end $$;
do $$ begin
if not exists (select 1 from pg_trigger where tgname='companies_set_updated_at') then create trigger companies_set_updated_at before update on public.companies for each row execute function public.set_current_timestamp_updated_at(); end if;
if not exists (select 1 from pg_trigger where tgname='company_members_set_updated_at') then create trigger company_members_set_updated_at before update on public.company_members for each row execute function public.set_current_timestamp_updated_at(); end if;
if not exists (select 1 from pg_trigger where tgname='company_settings_set_updated_at') then create trigger company_settings_set_updated_at before update on public.company_settings for each row execute function public.set_current_timestamp_updated_at(); end if;
if not exists (select 1 from pg_trigger where tgname='company_document_settings_set_updated_at') then create trigger company_document_settings_set_updated_at before update on public.company_document_settings for each row execute function public.set_current_timestamp_updated_at(); end if;
if not exists (select 1 from pg_trigger where tgname='user_preferences_set_updated_at') then create trigger user_preferences_set_updated_at before update on public.user_preferences for each row execute function public.set_current_timestamp_updated_at(); end if;
end $$;
insert into public.companies(owner_user_id,name) select e.user_id,coalesce(nullif(e.data #>> '{entreprise,identity,legalName}',''),nullif(e.data #>> '{onboarding,company,name}',''),'Entreprise Piloz') from public.etat e where not exists (select 1 from public.companies c where c.owner_user_id=e.user_id);
insert into public.company_members(company_id,user_id,role) select c.id,c.owner_user_id,'owner' from public.companies c where not exists (select 1 from public.company_members cm where cm.company_id=c.id and cm.user_id=c.owner_user_id);
insert into public.user_preferences(user_id,company_id,onboarding_completed) select c.owner_user_id,c.id,false from public.companies c where not exists (select 1 from public.user_preferences p where p.user_id=c.owner_user_id);
